// ===== Validar/Normalizar Input — 8D bloqueos =====
const TEST_OPS = 'ops'; // marcador de entorno: 'test' o 'ops'

const MAPA_CABANAS = { 'Bamboo': 1, 'Madre Selva': 2, 'Arrebol': 3, 'Guatemala': 4, 'Tokio': 5 };
const MAPA_MOTIVO = {
  'Mantenimiento': 'mantenimiento',
  'Uso propio': 'uso_propio',
  'Tormenta / clima': 'tormenta',
  'Overbooking': 'overbooking',
  'Otro': 'otro'
};

const f = $input.first().json;

const cabanaLabel = (f['Cabaña'] || f['Cabana'] || '').toString().trim();
const fechaDesde  = (f['Fecha desde'] || '').toString().trim().slice(0, 10);
const fechaHasta  = (f['Fecha hasta / liberación'] || f['Fecha hasta'] || '').toString().trim().slice(0, 10);
const motivoLabel = (f['Motivo'] || '').toString().trim();
const descripcion = (f['Descripción'] || f['Descripcion'] || '').toString().trim();
const operadorLabel = (f['Creado por'] || '').toString().trim();

const idCabana = MAPA_CABANAS[cabanaLabel];
const motivo = MAPA_MOTIVO[motivoLabel];
const operador = operadorLabel.toLowerCase().replace(/\s+/g, '');

let errorCapa = null;
if (!cabanaLabel || idCabana === undefined) errorCapa = 'cabana';
else if (!fechaDesde || !fechaHasta) errorCapa = 'fechas_faltan';
else if (fechaHasta <= fechaDesde) errorCapa = 'fechas_orden';
else if (!motivo) errorCapa = 'motivo';
else if (!operador) errorCapa = 'operador';

const sourceEvent = 'n8n_' + TEST_OPS + '_w8d_bloqueo_' + (operador || 'desconocido') + '_manual';

return [{
  json: {
    ok_capa: errorCapa === null,
    error_capa: errorCapa,
    id_cabana: idCabana !== undefined ? String(idCabana) : '',
    cabana_label: cabanaLabel,
    fecha_desde: fechaDesde,
    fecha_hasta: fechaHasta,
    motivo: motivo || '',
    motivo_label: motivoLabel,
    descripcion: descripcion,
    creado_por: operador,
    source_event: sourceEvent
  }
}];

// ===== Build Payload — 8D bloqueos =====
const v = $input.first().json;
const payload = {
  id_cabana:    v.id_cabana,
  fecha_desde:  v.fecha_desde,
  fecha_hasta:  v.fecha_hasta,
  motivo:       v.motivo,
  descripcion:  v.descripcion || '',
  creado_por:   v.creado_por,
  source_event: v.source_event
};
return [{ json: { payload, ctx: {
  cabana_label: v.cabana_label,
  fecha_desde: v.fecha_desde,
  fecha_hasta: v.fecha_hasta,
  motivo_label: v.motivo_label
} } }];

// ===== Normalize — envelope tras crear_bloqueo =====
let raw;
try { raw = $input.first().json; } catch (e) { raw = null; }

// El nodo Postgres devuelve el jsonb dentro de la columna 'resultado'.
// Si no viene, es error técnico del nodo.
const item = raw && raw.resultado !== undefined ? raw.resultado : raw;

let ctx = {};
try { ctx = $('Build Payload').first().json.ctx || {}; } catch (e) { ctx = {}; }

const tieneOk = item && Object.prototype.hasOwnProperty.call(item, 'ok');
const huboErrorTecnico = !item || !tieneOk;

let envelope;
if (huboErrorTecnico) {
  envelope = { tipo: 'tecnico', ok: false };
} else if (item.ok === true) {
  envelope = { tipo: 'exito', ok: true, id_bloqueo: item.id_bloqueo, id_cabana: item.id_cabana, tipo_bloqueo: item.tipo_bloqueo };
} else {
  const err = item.error;
  const conflictos = ['conflicto_con_reserva', 'conflicto_con_prereserva', 'bloqueo_solapado'];
  const familia = conflictos.includes(err) ? 'conflicto' : 'entrada';
  envelope = { tipo: 'negocio', ok: false, error: err, familia };
}
envelope.ctx = ctx;
return [{ json: envelope }];

// ===== Build Response — mensaje único al operador =====
const e = $input.first().json;
const ctx = e.ctx || {};

function fmtFecha(ymd) {
  if (!ymd) return '';
  const p = String(ymd).slice(0,10).split('-');
  if (p.length !== 3) return ymd;
  return p[2] + '/' + p[1];
}
function diaAnterior(ymd) {
  if (!ymd) return '';
  const d = new Date(String(ymd).slice(0,10) + 'T00:00:00Z');
  d.setUTCDate(d.getUTCDate() - 1);
  return d.toISOString().slice(0,10);
}

let title, message;

if (e.tipo === 'exito') {
  const ultimoInclusive = diaAnterior(ctx.fecha_hasta);
  title = 'Bloqueo creado';
  message = ctx.cabana_label + ' bloqueada desde el ' + fmtFecha(ctx.fecha_desde) + ' hasta el ' + fmtFecha(ultimoInclusive) + ' inclusive. Se libera el ' + fmtFecha(ctx.fecha_hasta) + '. (Motivo: ' + ctx.motivo_label + '. N° ' + e.id_bloqueo + '.)';
} else if (e.tipo === 'negocio' && e.familia === 'conflicto') {
  title = 'No se pudo crear el bloqueo';
  message = 'Esas fechas no están disponibles para bloquear. Revisá el calendario.';
} else if (e.tipo === 'negocio' && e.familia === 'entrada') {
  title = 'Revisá los datos';
  switch (e.error) {
    case 'fechas_invalidas':
      message = "La fecha 'hasta / liberación' tiene que ser posterior a la fecha 'desde'."; break;
    case 'cabana_no_existe':
      message = 'La cabaña seleccionada no es válida.'; break;
    case 'motivo_invalido':
      message = 'El motivo seleccionado no es válido.'; break;
    case 'payload_invalido':
      message = 'Faltan datos obligatorios. Completá cabaña, fechas, motivo y operador.'; break;
    default:
      message = 'Hay un dato inválido. Revisá el formulario.';
  }
} else {
  title = 'Problema técnico';
  message = 'No se pudo registrar el bloqueo por un problema técnico. Reintentá en unos minutos.';
}

return [{ json: { completionTitle: title, completionMessage: message } }];

const v = $input.first().json;
const map = { fechas_orden: 'fechas_invalidas', fechas_faltan: 'payload_invalido', cabana: 'cabana_no_existe', motivo: 'motivo_invalido', operador: 'payload_invalido' };
const err = map[v.error_capa] || 'payload_invalido';
return [{ json: { tipo: 'negocio', ok: false, error: err, familia: 'entrada', ctx: { cabana_label: v.cabana_label, fecha_desde: v.fecha_desde, fecha_hasta: v.fecha_hasta, motivo_label: v.motivo_label } } }];
